/* ─── Process raw data into full game objects ─── */

function generateLongDescription(game) {
  const openers = {
    Action: `${game.title} is a thrilling action game that pushes your skills to the limit.`,
    Puzzle: `${game.title} challenges your mind with creative and engaging puzzle mechanics.`,
    Racing: `${game.title} puts you behind the wheel in intense high-speed competitions.`,
    Sports: `${game.title} brings the excitement of competitive sports right to your device.`,
    Arcade: `${game.title} delivers classic arcade fun with a modern twist.`,
    Casual: `${game.title} offers a relaxing yet engaging gaming experience for all ages.`,
    Strategy: `${game.title} tests your tactical thinking and strategic planning abilities.`,
    Adventure: `${game.title} takes you on an unforgettable journey through mysterious worlds.`,
  };
  return `${openers[game.cat]} ${game.short} With ${game.dl} downloads and a ${game.r}-star rating, it is loved by players worldwide. Download now and join the community!`;
}

export const games = rawGames.map((g, index) => {
  const slug = g.title.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/-+$/, '');
  const id = String(index + 1);
  return {
    id,
    slug,
    title: g.title,
    category: g.cat,
    rating: g.r,
    score: g.r.toFixed(1),
    downloads: g.dl,
    developer: g.dev,
    age: g.age,
    version: g.ver,
    price: g.price,
    shortDescription: g.short,
    longDescription: generateLongDescription(g),
    tags: g.tags,
    featured: g.feat || false,
    trending: g.trend || false,
    icon: g.img,
    thumbnail: g.img,
    screenshots: screenshotMap[g.iid] || [
      `https://placehold.co/800x450/6d28d9/white?text=${encodeURIComponent(g.title)}`,
    ],
    androidUrl: g.apkg ? `https://play.google.com/store/apps/details?id=${g.apkg}` : null,
    iosUrl: g.iid ? `https://apps.apple.com/app/id${g.iid}` : null,
  };
});

/* ─── Derived data ─── */

export const categories = [...new Set(games.map((g) => g.category))];

/* ─── Helper functions ─── */

export function getGameBySlug(slug) {
  return games.find((g) => g.slug === slug) || null;
}

export function getGamesByCategory(category) {
  return games.filter((g) => g.category === category);
}

export function searchGames(query) {
  const q = query.toLowerCase().trim();
  if (!q) return [];
  return games.filter(
    (g) =>
      g.title.toLowerCase().includes(q) ||
      g.category.toLowerCase().includes(q) ||
      g.tags.some((t) => t.toLowerCase().includes(q))
  );
}

export function getRelatedGames(game, limit = 10) {
  return games
    .filter(
      (g) =>
        g.id !== game.id &&
        (g.category === game.category || g.tags.some((t) => game.tags.includes(t)))
    )
    .slice(0, limit);
}

export function getSidebarGames(excludeId, limit = 15) {
  return games.filter((g) => g.id !== excludeId).slice(0, limit);
}

export function getFeaturedGames(limit = 10) {
  return games.filter((g) => g.featured).slice(0, limit);
}

export function getTrendingGames(limit = 10) {
  return games.filter((g) => g.trending).slice(0, limit);
}
